// ============================================================================
// Permission Constants
// ============================================================================

/// Permission: read
pub const PSYNC_PERM_READ: u32 = 1;
/// Permission: create
pub const PSYNC_PERM_CREATE: u32 = 2;
/// Permission: modify
pub const PSYNC_PERM_MODIFY: u32 = 4;
/// Permission: delete
pub const PSYNC_PERM_DELETE: u32 = 8;
