// ============================================================================
// Helper Functions
// ============================================================================

/// Convert a sync status code to a human-readable string.
pub fn status_to_string(status: u32) -> &'static str {
    match status {
        PSTATUS_READY => "Ready",
        PSTATUS_DOWNLOADING => "Downloading",
        PSTATUS_UPLOADING => "Uploading",
        PSTATUS_DOWNLOADINGANDUPLOADING => "Syncing",
        PSTATUS_LOGIN_REQUIRED => "Login Required",
        PSTATUS_BAD_LOGIN_DATA => "Invalid Credentials",
        PSTATUS_BAD_LOGIN_TOKEN => "Invalid Token",
        PSTATUS_ACCOUNT_FULL => "Account Full",
        PSTATUS_DISK_FULL => "Disk Full",
        PSTATUS_PAUSED => "Paused",
        PSTATUS_STOPPED => "Stopped",
        PSTATUS_OFFLINE => "Offline",
        PSTATUS_CONNECTING => "Connecting",
        PSTATUS_SCANNING => "Scanning",
        PSTATUS_USER_MISMATCH => "User Mismatch",
        _ => "Unknown",
    }
}

/// Check if a status indicates the client is actively syncing.
pub fn is_syncing(status: u32) -> bool {
    matches!(
        status,
        PSTATUS_DOWNLOADING | PSTATUS_UPLOADING | PSTATUS_DOWNLOADINGANDUPLOADING
    )
}

/// Check if a status indicates an error condition.
pub fn is_error_status(status: u32) -> bool {
    matches!(
        status,
        PSTATUS_LOGIN_REQUIRED
            | PSTATUS_BAD_LOGIN_DATA
            | PSTATUS_BAD_LOGIN_TOKEN
            | PSTATUS_ACCOUNT_FULL
            | PSTATUS_DISK_FULL
            | PSTATUS_USER_MISMATCH
    )
}

/// Check if a status indicates the client needs user action.
pub fn needs_user_action(status: u32) -> bool {
    matches!(
        status,
        PSTATUS_LOGIN_REQUIRED
            | PSTATUS_BAD_LOGIN_DATA
            | PSTATUS_BAD_LOGIN_TOKEN
            | PSTATUS_USER_MISMATCH
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_status_to_string() {
        assert_eq!(status_to_string(PSTATUS_READY), "Ready");
        assert_eq!(status_to_string(PSTATUS_DOWNLOADING), "Downloading");
        assert_eq!(status_to_string(PSTATUS_OFFLINE), "Offline");
        assert_eq!(status_to_string(999), "Unknown");
    }

    #[test]
    fn test_is_syncing() {
        assert!(is_syncing(PSTATUS_DOWNLOADING));
        assert!(is_syncing(PSTATUS_UPLOADING));
        assert!(is_syncing(PSTATUS_DOWNLOADINGANDUPLOADING));
        assert!(!is_syncing(PSTATUS_READY));
        assert!(!is_syncing(PSTATUS_OFFLINE));
    }

    #[test]
    fn test_is_error_status() {
        assert!(is_error_status(PSTATUS_LOGIN_REQUIRED));
        assert!(is_error_status(PSTATUS_BAD_LOGIN_DATA));
        assert!(is_error_status(PSTATUS_ACCOUNT_FULL));
        assert!(!is_error_status(PSTATUS_READY));
        assert!(!is_error_status(PSTATUS_DOWNLOADING));
    }

    #[test]
    fn test_needs_user_action() {
        assert!(needs_user_action(PSTATUS_LOGIN_REQUIRED));
        assert!(needs_user_action(PSTATUS_BAD_LOGIN_DATA));
        assert!(!needs_user_action(PSTATUS_READY));
        assert!(!needs_user_action(PSTATUS_ACCOUNT_FULL));
    }

    #[test]
    fn test_sync_type_constants() {
        assert!(PSYNC_DOWNLOAD_ONLY >= PSYNC_SYNCTYPE_MIN);
        assert!(PSYNC_DOWNLOAD_ONLY <= PSYNC_SYNCTYPE_MAX);
        assert!(PSYNC_UPLOAD_ONLY >= PSYNC_SYNCTYPE_MIN);
        assert!(PSYNC_UPLOAD_ONLY <= PSYNC_SYNCTYPE_MAX);
        assert!(PSYNC_FULL >= PSYNC_SYNCTYPE_MIN);
        assert!(PSYNC_FULL <= PSYNC_SYNCTYPE_MAX);
    }

    #[test]
    fn test_permission_constants() {
        assert_eq!(PSYNC_PERM_ALL, 0b1111);
        assert_eq!(
            PSYNC_PERM_WRITE,
            PSYNC_PERM_CREATE | PSYNC_PERM_MODIFY | PSYNC_PERM_DELETE
        );
    }
}
